import{_ as a,c as i,o as e,a4 as s}from"./chunks/framework.BmdFiWrL.js";const u=JSON.parse('{"title":"设置","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"guide/settings.md","filePath":"guide/settings.md","lastUpdated":1780405010000}'),o={name:"guide/settings.md"},t=s(`<h1 id="设置" tabindex="-1">设置 <a class="header-anchor" href="#设置" aria-label="Permalink to &quot;设置&quot;">​</a></h1><p><strong>登录管理页面后，点击头像 → 系统设置，即可进入设置页面。</strong></p><hr><h2 id="系统配置" tabindex="-1">系统配置 <a class="header-anchor" href="#系统配置" aria-label="Permalink to &quot;系统配置&quot;">​</a></h2><h3 id="站点名称" tabindex="-1">站点名称 <a class="header-anchor" href="#站点名称" aria-label="Permalink to &quot;站点名称&quot;">​</a></h3><p>在此项中可以自定义站点标题，便于识别和管理。</p><h3 id="语言设置" tabindex="-1">语言设置 <a class="header-anchor" href="#语言设置" aria-label="Permalink to &quot;语言设置&quot;">​</a></h3><p>设置软件的语言，主要影响通知与错误信息。</p><p>同时可以联动网页界面，实时更改语言。</p><h3 id="自定义代码" tabindex="-1">自定义代码 <a class="header-anchor" href="#自定义代码" aria-label="Permalink to &quot;自定义代码&quot;">​</a></h3><p>此项用于在网页界面中添加自定义样式或脚本代码，例如修改 Logo、背景图、主题、外链或统计代码。</p><p>此项分为两类：</p><ul><li><strong>用户前端自定义代码</strong>：对应配置文件中的 <code>custom_code</code>，会注入公开访问的用户前端。</li><li><strong>管理前端自定义代码</strong>：对应配置文件中的 <code>custom_code_dashboard</code>，只会注入登录后的管理前端。</li></ul><p>下面这些全局变量仅由用户前端读取，放入管理前端自定义代码不会生效。请在用户前端自定义代码中通过 <code>&lt;script&gt;...&lt;/script&gt;</code> 设置；布尔值使用 <code>true</code> / <code>false</code>，不要写成字符串。</p><ul><li><code>window.CustomBackgroundImage</code>：桌面端背景图 URL。</li><li><code>window.CustomMobileBackgroundImage</code>：移动端背景图 URL，未设置时会沿用桌面端背景图。</li><li><code>window.CustomLogo</code>：Logo 图片 URL。</li><li><code>window.CustomDesc</code>：首页描述文本。</li><li><code>window.CustomLinks</code>：自定义外链，值必须是可被 <code>JSON.parse</code> 解析的 JSON 字符串，格式为 <code>[{&quot;name&quot;:&quot;GitHub&quot;,&quot;link&quot;:&quot;https://github.com/nezhahq/nezha&quot;}]</code>。</li><li><code>window.ForceTheme</code>：强制默认颜色主题，值为 <code>&quot;light&quot;</code> 或 <code>&quot;dark&quot;</code>。</li><li><code>window.ShowNetTransfer</code>：是否在服务器卡片显示上下行流量。</li><li><code>window.DisableAnimatedMan</code>：是否关闭默认动画人物插图。</li><li><code>window.CustomIllustration</code>：自定义插图 URL。设置后会替换默认插图，通常不需要再启用 <code>window.DisableAnimatedMan</code>。</li><li><code>window.FixedTopServerName</code>：是否固定顶部服务器名称。</li><li><code>window.ForceUseSvgFlag</code>：是否强制使用 SVG 旗帜。</li><li><code>window.ForceShowServices</code>：是否默认展开首页服务监控面板。</li><li><code>window.ForceCardInline</code>：是否在非移动端强制使用服务器横向列表布局；移动端仍会使用卡片布局。</li><li><code>window.ForceShowMap</code>：是否默认展开首页地图。</li><li><code>window.ForcePeakCutEnabled</code>：是否默认开启网络图表的峰值裁剪，用于降低突发尖峰对图表可读性的影响。</li></ul><p>用户前端示例：</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  window.CustomLogo </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://example.com/logo.png&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  window.CustomDesc </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;My Monitor&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  window.CustomLinks </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> JSON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">stringify</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { name: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;GitHub&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, link: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://github.com/nezhahq/nezha&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  window.ForceTheme </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;dark&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  window.ForceShowServices </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><ul><li>管理前端 <ol><li><code>window.DisableAnimatedMan</code>：布尔值，开/关动画人物插图</li></ol></li></ul><h3 id="主题" tabindex="-1">主题 <a class="header-anchor" href="#主题" aria-label="Permalink to &quot;主题&quot;">​</a></h3><p>主题设置用于选择用户前端展示模板，对应配置文件中的 <a href="/configuration/dashboard.html#user_template"><code>user_template</code></a>。管理前端模板对应 <a href="/configuration/dashboard.html#admin_template"><code>admin_template</code></a>，通常保持默认即可。</p><p>内置主题由官方维护；社区主题来自社区贡献，可能不会随 Dashboard 版本同步更新。使用社区主题前请确认来源可信、兼容当前版本，并了解其自定义代码、外链资源或样式变更带来的风险。</p><h3 id="agent-对接地址" tabindex="-1">Agent 对接地址 <a class="header-anchor" href="#agent-对接地址" aria-label="Permalink to &quot;Agent 对接地址&quot;">​</a></h3><ul><li>此项为使用一键脚本安装 Agent 的必要设置。</li><li>设置内容为你希望使用的 Agent 连接地址，例如：<code>data.example.com:8008</code>。</li><li>如果 Agent 通过 HTTPS、Dashboard 内置 HTTPS 或已在反向代理/CDN 上完成 TLS 终结连接，请启用 <strong>Agent 使用 TLS 连接</strong>，生成的安装命令会带上 TLS 参数。</li><li>如果 Agent 直连明文 <code>host:port</code>，请不要启用 TLS，否则安装命令会让 Agent 按 TLS 方式连接，可能导致无法上线。</li><li>详情请参考 <a href="/guide/agent.html#准备工作">Agent 安装准备工作</a>。</li></ul><h3 id="dashboard-保留域名" tabindex="-1">Dashboard 保留域名 <a class="header-anchor" href="#dashboard-保留域名" aria-label="Permalink to &quot;Dashboard 保留域名&quot;">​</a></h3><p>用于声明 Dashboard 对外访问使用的域名，防止普通成员在 NAT 中创建与 Dashboard 入口冲突的域名。多个域名使用英文逗号分隔。配置字段为 <a href="/configuration/dashboard.html#reserved_hosts"><code>reserved_hosts</code></a>。</p><h3 id="ddns-的自定义公共-dns-名称服务器" tabindex="-1">DDNS 的自定义公共 DNS 名称服务器 <a class="header-anchor" href="#ddns-的自定义公共-dns-名称服务器" aria-label="Permalink to &quot;DDNS 的自定义公共 DNS 名称服务器&quot;">​</a></h3><p>用于 DDNS 功能查询域名 SOA 记录，如不填则采用内置列表。</p><h3 id="前端真实-ip-请求头" tabindex="-1">前端真实 IP 请求头 <a class="header-anchor" href="#前端真实-ip-请求头" aria-label="Permalink to &quot;前端真实 IP 请求头&quot;">​</a></h3><p>用于识别访问管理前端和用户前端的真实客户端 IP。在线用户、审计记录、登录防爆破和 Web 应用防火墙都依赖它。</p><p>直连公网时选择 <strong>使用直连 IP</strong>；通过 Cloudflare 时通常填写 <code>CF-Connecting-IP</code>；通过 Nginx、Caddy、Apache 等反向代理时，需要代理传递 <code>X-Real-IP</code>、<code>nz-realip</code> 或其它同名 Header。完整配置场景、反向代理示例、验证和恢复方法见 <a href="/guide/q12.html">前端真实 IP 请求头</a>。</p><h3 id="agent-真实-ip-请求头" tabindex="-1">Agent 真实 IP 请求头 <a class="header-anchor" href="#agent-真实-ip-请求头" aria-label="Permalink to &quot;Agent 真实 IP 请求头&quot;">​</a></h3><ul><li><code>CF-Connecting-IP</code> 是一个用于获取 Agent 真实 IP 的请求头字段。</li><li>当 Agent 通过 Cloudflare CDN 代理连接 Dashboard 时，启用此功能可以让源服务器正确识别 Agent 的真实 IP。</li></ul><h3 id="mcp-开关" tabindex="-1">MCP 开关 <a class="header-anchor" href="#mcp-开关" aria-label="Permalink to &quot;MCP 开关&quot;">​</a></h3><p>用于启用或关闭 Dashboard 的 MCP 入口。启用后可使用 PAT 调用 <code>POST /mcp</code>；关闭时会拒绝新的 MCP 请求并中断相关传输。配置字段为 <a href="/configuration/dashboard.html#enable_mcp"><code>enable_mcp</code></a>，认证和权限说明见 <a href="/guide/api.html#mcp-接入">API 接口 - MCP 接入</a>。</p><h3 id="ip-变更提醒" tabindex="-1">IP 变更提醒 <a class="header-anchor" href="#ip-变更提醒" aria-label="Permalink to &quot;IP 变更提醒&quot;">​</a></h3><p>此功能允许在服务器 IP 地址变更时发送通知，设置步骤如下：</p><h4 id="配置选项" tabindex="-1">配置选项 <a class="header-anchor" href="#配置选项" aria-label="Permalink to &quot;配置选项&quot;">​</a></h4><ol><li><p><strong>覆盖范围</strong><br> 选择一条规则以确定需要监控哪些服务器。</p></li><li><p><strong>特定服务器</strong><br> 配合覆盖范围设置。覆盖范围为 <strong>覆盖全部</strong> 时，这里表示 <strong>排除特定服务器</strong>；覆盖范围为 <strong>忽略全部</strong> 时，这里表示 <strong>仅特定服务器</strong>。</p></li><li><p><strong>提醒发送至通知分组</strong><br> 选择通知方式（通知方式需提前在“通知”页中设置）。</p></li><li><p><strong>启用功能</strong><br> 设置完成后，勾选 <strong>启用</strong> 才会使通知生效。</p></li><li><p><strong>通知中显示完整 IP 地址</strong><br> 默认情况下，IP 变更通知会隐藏完整 IP 地址。<br> 如需显示完整 IP 地址，可勾选此选项。</p></li></ol><hr><h2 id="api-tokens" tabindex="-1">API Tokens <a class="header-anchor" href="#api-tokens" aria-label="Permalink to &quot;API Tokens&quot;">​</a></h2><p>此标签页用于创建和吊销 Personal Access Token（PAT）。PAT 适合自动化脚本、CI、LLM 工具和 MCP 客户端使用。</p><p>普通成员进入设置页时只会看到 <strong>API Tokens</strong> 标签页；其它系统配置、用户管理、在线用户和 Web 应用防火墙等标签页仅管理员可见。</p><p>创建 Token 时可以选择 scope、可访问的服务器 ID 白名单和过期时间。Token 明文只会在创建成功后显示一次；后续列表只会展示权限、服务器白名单、过期时间、最后使用时间和最后使用 IP 等元信息。认证格式和 scope 说明见 <a href="/guide/api.html#personal-access-token-pat">API 接口 - Personal Access Token</a>。</p><hr><h2 id="用户管理" tabindex="-1">用户管理 <a class="header-anchor" href="#用户管理" aria-label="Permalink to &quot;用户管理&quot;">​</a></h2><p>此标签页允许为 Dashboard 添加多个用户。</p><p>具体功能请参考 <a href="/guide/user.html">多用户</a>。</p><hr><h2 id="在线用户" tabindex="-1">在线用户 <a class="header-anchor" href="#在线用户" aria-label="Permalink to &quot;在线用户&quot;">​</a></h2><p>查看当前连接到前台的游客 / 用户信息，包含 <strong>IP</strong> 及 <strong>连接时间</strong>，并可以手动封禁用户；管理员也可以批量封禁选中的在线用户。</p><hr><h2 id="web-应用防火墙" tabindex="-1">Web 应用防火墙 <a class="header-anchor" href="#web-应用防火墙" aria-label="Permalink to &quot;Web 应用防火墙&quot;">​</a></h2><p>Web 应用防火墙依赖 <strong>前端真实 IP 请求头</strong> 识别来源 IP。配置真实 IP Header 前，请先阅读 <a href="/guide/q12.html">前端真实 IP 请求头</a>，确认 Dashboard 读取到的是真实客户端 IP。</p><p>可以查看当前的封禁条目，并提供一些有用的信息：</p><ul><li><strong>IP</strong> 被封禁者的 IP。</li><li><strong>封禁标识</strong> 被封禁者尝试攻击的资源标识，与 IP 一起作为封禁条目的标识。一般情况下为用户 ID，但也存在以下特殊情况： <ol><li>尝试破解 gRPC 连接密钥；</li><li>尝试破解 API Token；</li><li>尝试登录不存在的用户；</li><li>手动封禁（通过“在线用户”页面）。</li></ol></li><li><strong>计数</strong> 此封禁条目的封禁次数，数量越多则封禁时间越长。</li><li><strong>封禁原因</strong> 此封禁条目最后一次的封禁原因。</li><li><strong>封禁时间</strong> 此封禁条目最后一次的封禁时间。</li></ul><p>如果当前用户为管理员，便可以手动删除封禁条目，也可以批量删除选中的封禁条目。</p>`,56),n=[t];function l(r,d,h,p,c,g){return e(),i("div",null,n)}const E=a(o,[["render",l]]);export{u as __pageData,E as default};
